# Unit Tests for `partial` Function

```python
import pytest


def partial(fn, *partial_args, **partial_kwargs):
    def wrapper(*args, **kwargs):
        merged = {**partial_kwargs, **kwargs}
        return fn(*partial_args, *args, **merged)
    return wrapper


class TestPartialHappyPath:
    """Test cases for normal, expected usage."""

    def test_partial_with_positional_args_only(self):
        """Test partial application with only positional arguments."""
        def add(a, b, c):
            return a + b + c

        add_5 = partial(add, 5)
        assert add_5(3, 2) == 10

    def test_partial_with_keyword_args_only(self):
        """Test partial application with only keyword arguments."""
        def greet(name, greeting="Hello"):
            return f"{greeting}, {name}!"

        greet_hi = partial(greet, greeting="Hi")
        assert greet_hi("Alice") == "Hi, Alice!"

    def test_partial_with_both_positional_and_keyword_args(self):
        """Test partial application with both positional and keyword arguments."""
        def format_string(prefix, value, suffix=""):
            return f"{prefix}{value}{suffix}"

        format_with_prefix = partial(format_string, ">>", suffix="<<")
        assert format_with_prefix("test") == ">>test<<"

    def test_partial_multiple_positional_args(self):
        """Test partial with multiple positional arguments."""
        def multiply(a, b, c, d):
            return a * b * c * d

        partial_fn = partial(multiply, 2, 3)
        assert partial_fn(4, 5) == 120

    def test_partial_multiple_keyword_args(self):
        """Test partial with multiple keyword arguments."""
        def create_user(name, age, email, active=True):
            return {"name": name, "age": age, "email": email, "active": active}

        create_inactive_user = partial(create_user, active=False)
        result = create_inactive_user("Bob", 30, "bob@example.com")
        assert result == {"name": "Bob", "age": 30, "email": "bob@example.com", "active": False}

    def test_partial_override_keyword_args(self):
        """Test that wrapper kwargs override partial kwargs."""
        def greet(name, greeting="Hello"):
            return f"{greeting}, {name}!"

        greet_hi = partial(greet, greeting="Hi")
        assert greet_hi("Alice", greeting="Hey") == "Hey, Alice!"

    def test_partial_with_no_args(self):
        """Test partial with no partial arguments (identity-like behavior)."""
        def add(a, b):
            return a + b

        add_partial = partial(add)
        assert add_partial(5, 3) == 8

    def test_partial_with_lambda(self):
        """Test partial works with lambda functions."""
        fn = partial(lambda x, y: x * y, 3)
        assert fn(4) == 12

    def test_partial_chainable(self):
        """Test that partial can be applied multiple times."""
        def add_three(a, b, c):
            return a + b + c

        add_5 = partial(add_three, 5)
        add_5_and_3 = partial(add_5, 3)
        assert add_5_and_3(2) == 10


